export default AdminLayout;

import React, { useState, useEffect } from "react";
import { ThemeContext } from "./ThemeContext";

const defaultConfig = {
  theme: "light",
  layout: { mode: "fluid" },
  topbar: { color: "dark" },
  menu: { color: "light" },
  sidenav: { size: "default" },
};

export const ThemeProvider = ({ children }) => {
  const savedConfig = sessionStorage.getItem("__UPLON_CONFIG__");
  const [config, setConfig] = useState(
    savedConfig ? JSON.parse(savedConfig) : defaultConfig
  );

  const applyConfigToHTML = (cfg) => {
    const html = document.documentElement;
    html.setAttribute("data-bs-theme", cfg.theme);
    html.setAttribute("data-layout-mode", cfg.layout.mode);
    html.setAttribute("data-topbar-color", cfg.topbar.color);
    html.setAttribute("data-menu-color", cfg.menu.color);
    html.setAttribute("data-sidenav-size", cfg.sidenav.size);
    sessionStorage.setItem("__UPLON_CONFIG__", JSON.stringify(cfg));
  };

  useEffect(() => {
    applyConfigToHTML(config);
  }, [config]);

  const toggleSidebar = () => {
    const html = document.documentElement;
    html.classList.toggle("sidebar-enable");

    const newSize =
      html.getAttribute("data-sidenav-size") === "default"
        ? "condensed"
        : "default";

    setConfig((prev) => ({
      ...prev,
      sidenav: { ...prev.sidenav, size: newSize },
    }));
  };

  const toggleTheme = () => {
    setConfig((prev) => ({
      ...prev,
      theme: prev.theme === "light" ? "dark" : "light",
    }));
  };

  const updateConfig = (key, value) => {
    setConfig((prev) => ({ ...prev, [key]: value }));
  };

  return (
    <ThemeContext.Provider
      value={{ config, setConfig, updateConfig, toggleSidebar, toggleTheme }}
    >
      {children}
    </ThemeContext.Provider>
  );
};

