import React, { useEffect, useState } from "react";
import SimpleBar from "simplebar-react";
import { NavLink, useLocation } from "react-router-dom";
import { Button } from "antd";
import { useSelector } from "react-redux";
import { ChevronRight } from "lucide-react";

import { menuItems } from "../constants/menu.constant";
import { getHighestRole, ROLE_HOME } from "../constants/role.constant";
import "simplebar-react/dist/simplebar.min.css";

const SideNav = ({ isCondensed }) => {
  const { pathname } = useLocation();
  const roles = useSelector((state) => state.auths?.user?.roles);

  const [openMenus, setOpenMenus] = useState({});

  const toggleMenu = (id) => {
    setOpenMenus((prev) => ({
      ...prev,
      [id]: !prev[id],
    }));
  };

  const hasPermission = (itemRoles) => {
    if (!itemRoles) return true;
    if (!Array.isArray(roles)) return false;
    return itemRoles.some((r) => roles.includes(r));
  };

  const filteredMenu = menuItems
    .map((item) => {
      if (item.type === "submenu") {
        const filteredChildren = item.children.filter((child) =>
          hasPermission(child.roles)
        );

        if (!hasPermission(item.roles) && filteredChildren.length === 0) {
          return null;
        }

        return { ...item, children: filteredChildren };
      }

      if (!hasPermission(item.roles)) return null;

      return item;
    })
    .filter(Boolean);

  const highestRole = getHighestRole(roles);
  const home = ROLE_HOME[highestRole] || "/403";

  useEffect(() => {
    const newOpenMenus = {};

    menuItems.forEach((item) => {
      if (item.type === "submenu") {
        const hasActiveChild = item.children.some((c) => pathname === c.href);
        if (hasActiveChild) {
          newOpenMenus[item.id] = true;
        }
      }
    });

    setOpenMenus((prev) => ({ ...prev, ...newOpenMenus }));
  }, [pathname]);

  return (
    <div className={`sidenav-menu ${isCondensed ? "sidenav-condensed" : ""}`}>
      {/* Logo */}
      <a href={home} className="sidenav-logo">
        <img
          src="/assets/images/logoPhucAn.png"
          alt="PhucAn logo"
          className="sidenav-logo-img"
        />
      </a>

      {/* Close button */}
      <Button
        type="text"
        className="button-close-fullsidebar"
        icon={
          <svg
            xmlns="http://www.w3.org/2000/svg"
            width="24"
            height="24"
            viewBox="0 0 24 24"
            fill="none"
            stroke="currentColor"
            strokeWidth="2"
            strokeLinecap="round"
            strokeLinejoin="round"
          >
            <line x1="18" y1="6" x2="6" y2="18" />
            <line x1="6" y1="6" x2="18" y2="18" />
          </svg>
        }
      />

      {/* Scrollable menu */}
      <SimpleBar style={{ maxHeight: "100%" }} className="sidenav-scrollbar">
        <ul className="side-nav">
          {filteredMenu.map((item, idx) => {
            // --- TITLE (group label) ---
            if (item.type === "title") {
              return (
                <li key={idx} className="side-nav-title">
                  {item.label}
                </li>
              );
            }

            // --- ITEM ---
            if (item.type === "item") {
              const active = pathname === item.href;

              return (
                <li
                  key={idx}
                  className={`side-nav-item ${active ? "active" : ""}`}
                >
                  <NavLink
                    to={item.href}
                    className={`side-nav-link ${active ? "active" : ""}`}
                  >
                    <span className="menu-icon">{item.icon}</span>
                    <span className="menu-text">{item.label}</span>
                  </NavLink>
                </li>
              );
            }

            // --- SUBMENU ---
            if (item.type === "submenu") {
              const isOpen = openMenus[item.id] || false;

              return (
                <li key={idx} className="side-nav-item">
                  <button
                    className="side-nav-link side-nav-submenu-btn"
                    onClick={() => toggleMenu(item.id)}
                    type="button"
                  >
                    <span className="menu-icon">{item.icon}</span>
                    <span className="menu-text">{item.label}</span>
                    <ChevronRight
                      size={16}
                      strokeWidth={2}
                      className={`submenu-chevron ${isOpen ? "open" : ""}`}
                    />
                  </button>

                  {isOpen && (
                    <ul className="sub-menu">
                      {item.children.map((sub, subIdx) => {
                        const active = pathname === sub.href;
                        return (
                          <li
                            key={subIdx}
                            className={`side-nav-item ${active ? "active" : ""}`}
                          >
                            <NavLink
                              to={sub.href}
                              className={`side-nav-link side-nav-sub-link ${active ? "active" : ""}`}
                            >
                              <span className="menu-icon">{sub.icon}</span>
                              <span className="menu-text">{sub.label}</span>
                            </NavLink>
                          </li>
                        );
                      })}
                    </ul>
                  )}
                </li>
              );
            }

            return null;
          })}
        </ul>
      </SimpleBar>
    </div>
  );
};

export default SideNav;

