edits.newText:
/* ============================================
   SIDEBAR REDESIGN — white theme, modern professional
   ============================================ */

/* ---- Container ---- */
.sidenav-menu {
  width: 260px;
  min-width: 260px;
  background: #ffffff;
  display: flex;
  flex-direction: column;
  height: 100vh;
  position: relative;
  transition: width 0.3s cubic-bezier(0.4, 0, 0.2, 1),
    min-width 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  overflow: hidden;
  border-right: 1px solid #e5e7eb;
  flex-shrink: 0;
}

/* ---- Logo ---- */
.sidenav-logo {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px 16px 16px;
  text-decoration: none;
  flex-shrink: 0;
}

.sidenav-logo-img {
  height: 56px;
  width: auto;
  object-fit: contain;
  transition: height 0.3s ease;
}

/* ---- Close button (desktop fullscreen mode) ---- */
.button-close-fullsidebar {
  position: absolute !important;
  top: 12px !important;
  right: 12px !important;
  z-index: 10 !important;
  color: #9ca3af !important;
  width: 32px !important;
  height: 32px !important;
  padding: 0 !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  border-radius: 6px !important;
  transition: background 0.2s, color 0.2s !important;
}

.button-close-fullsidebar:hover {
  background: #f3f4f6 !important;
  color: #374151 !important;
}

/* ---- Scrollbar ---- */
.sidenav-scrollbar {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}

.sidenav-scrollbar .simplebar-track.simplebar-vertical {
  width: 4px;
}

.sidenav-scrollbar .simplebar-track.simplebar-vertical .simplebar-scrollbar::before {
  width: 4px;
  background: #d1d5db;
  border-radius: 4px;
  opacity: 1;
}

.sidenav-scrollbar .simplebar-track.simplebar-vertical .simplebar-scrollbar.simplebar-visible::before {
  opacity: 1;
}

/* ---- Side Nav list ---- */
.side-nav {
  list-style: none;
  margin: 0;
  padding: 8px 12px 24px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

/* ---- Group Labels ---- */
.side-nav .side-nav-title {
  text-transform: uppercase;
  letter-spacing: 1.5px;
  font-size: 11px !important;
  font-weight: 700 !important;
  color: #9ca3af !important;
  padding: 16px 12px 4px !important;
  pointer-events: none;
  cursor: default;
  white-space: nowrap;
  line-height: 1;
}

/* ---- Side Nav Item ---- */
.side-nav-item {
  position: relative;
}

/* ---- Side Nav Link (base) ---- */
.side-nav-link {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 12px;
  border-radius: 8px;
  text-decoration: none;
  color: #374151;
  font-size: 14px;
  font-weight: 500;
  line-height: 1.4;
  cursor: pointer;
  border: none;
  background: transparent;
  width: 100%;
  text-align: left;
  transition: background 0.15s ease, color 0.15s ease;
  white-space: nowrap;
}

.side-nav-link .menu-icon {
  color: #6b7280;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: color 0.15s ease;
}

.side-nav-link .menu-text {
  flex: 1;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: opacity 0.3s ease;
}

/* ---- Hover State ---- */
.side-nav-link:hover {
  background: #eff6ff;
  color: #1d4ed8;
}

.side-nav-link:hover .menu-icon {
  color: #1d4ed8;
}

/* ---- Active State ---- */
.side-nav-link.active {
  background: #1d4ed8;
  color: #ffffff;
}

.side-nav-link.active .menu-icon {
  color: #ffffff;
}

/* ---- Submenu Button ---- */
.side-nav-submenu-btn {
  position: relative;
}

.side-nav-submenu-btn .submenu-chevron {
  flex-shrink: 0;
  color: #9ca3af;
  transition: transform 0.25s ease, color 0.15s ease;
  margin-left: auto;
}

.side-nav-submenu-btn:hover .submenu-chevron {
  color: #1d4ed8;
}

.submenu-chevron.open {
  transform: rotate(90deg);
  color: #1d4ed8;
}

/* ---- Sub Menu ---- */
.sub-menu {
  list-style: none;
  margin: 0;
  padding: 0 0 4px 36px;
  display: flex;
  flex-direction: column;
  gap: 1px;
}

.side-nav-sub-link {
  padding: 8px 12px;
  font-size: 13.5px;
  font-weight: 400;
  color: #6b7280;
  border-radius: 8px;
}

.side-nav-sub-link:hover {
  background: #eff6ff;
  color: #1d4ed8;
}

.side-nav-sub-link:hover .menu-icon {
  color: #1d4ed8;
}

.side-nav-sub-link.active {
  background: #dbeafe;
  color: #1d4ed8;
  font-weight: 500;
}

.side-nav-sub-link.active .menu-icon {
  color: #1d4ed8;
}

/* ============================================
   COLLAPSE BEHAVIOR — icons only, smooth transition
   ============================================ */

.sidenav-condensed .sidenav-logo-img {
  height: 36px;
}

.sidenav-condensed .sidenav-logo {
  padding: 16px 0 12px;
  justify-content: center;
}

.sidenav-condensed .button-close-fullsidebar {
  display: none !important;
}

.sidenav-condensed .side-nav {
  padding: 8px 8px 24px;
  gap: 2px;
}

/* Hide all text in collapsed mode */
.sidenav-condensed .menu-text {
  opacity: 0;
  width: 0;
  overflow: hidden;
  pointer-events: none;
}

/* Submenu chevron hidden when collapsed */
.sidenav-condensed .submenu-chevron {
  display: none;
}

/* Sub-menu opens on click even when parent is collapsed */
.sidenav-condensed .sub-menu {
  padding-left: 0;
}

/* Collapse sidebar width */
.sidenav-condensed .sidenav-menu,
.sidenav-condensed .sidenav-menu {
  width: 68px;
  min-width: 68px;
}

/* Active items in collapsed mode get filled background */
.sidenav-condensed .side-nav-link.active {
  background: #1d4ed8;
  color: #ffffff;
  justify-content: center;
  padding: 10px;
}

.sidenav-condensed .side-nav-link.active .menu-icon {
  color: #ffffff;
}

/* Hover in collapsed mode */
.sidenav-condensed .side-nav-link:hover {
  background: #eff6ff;
  color: #1d4ed8;
  justify-content: center;
  padding: 10px;
}

.sidenav-condensed .side-nav-link:hover .menu-icon {
  color: #1d4ed8;
}

.sidenav-condensed .side-nav-submenu-btn {
  justify-content: center;
  padding: 10px;
}

.sidenav-condensed .side-nav-submenu-btn .menu-icon {
  margin: 0;
}

.sidenav-condensed .side-nav-sub-link {
  justify-content: center;
  padding: 8px 10px;
}

.sidenav-condensed .side-nav-title {
  display: none;
}

/* ============================================
   LEGACY / EXISTING — preserved from original
   ============================================ */

.dashboard-content-controls {
  display: flex;
  align-items: center;
  gap: 12px;
  flex-wrap: wrap;
}

